const PIECES_B = [{"id": "mobile-office", "name": "Mobile Office", "short": "Mobile Office", "icon": "💼", "color": "#8457E9", "blurb": "Can staff actually work securely from anywhere, or are they cutting corners?", "criteria": ["Remote or hybrid staff struggling to connect properly", "Field staff on unsecured connections reaching company data", "No real protection for anyone working outside the office"], "implicationQuestions": {"result_dev_lowneed": "When that change lands, what would it cost the business to not have the right setup already in place?", "result_mid_lowneed": "What would need to happen for that to go from possibly to something real?", "result_none_lowneed": "Is there anything on the horizon — growth, a new site — that could change that?", "result_hot_security": "What does that friction actually cost — time lost, workarounds, or risk you're carrying?", "result_mid_struggle": "Of all of that, which one thing would make the biggest difference if it just worked?", "result_hot_productivity": "How much time would you say gets lost each week just trying to stay in touch or get to the right system?", "result_dev_working": "If one of those remote devices were lost or compromised tomorrow, what would it expose?", "result_mid_working": "For whatever's not covered, what's the realistic worst case if a device without it went missing?", "result_none_working": "Good to hear — is that something you review periodically, or was it set up once and left alone?", "result_hot_field": "If a field device on an open network got compromised, what could someone reach from there?", "result_mid_field": "For the ones who don't have it yet, what are they typically accessing on the go?", "result_none_field": "Good — is that consistent for every field-based person, including anyone new who joins?"}, "needPayoff": {"lowneed_probe": "If the foundation was already in place before that change hits, would that make the transition painless?", "struggle_probe": "If hybrid staff worked as smoothly as if they were in the office, what would that be worth?", "working_probe": "If that risk was closed off without disrupting how well things currently work, would that be worth doing?", "field_probe": "If field staff had the same secure access as the office, what would that be worth in peace of mind?"}, "tree": {"start": {"type": "situation", "q": "How much of the team works outside the office — field, hybrid, multiple sites — and how well does that actually work today?", "options": [{"label": "Mostly office‑based, hybrid isn't really a thing here", "next": "lowneed_probe"}, {"label": "We have hybrid or remote staff and it's a struggle", "next": "struggle_probe"}, {"label": "We have hybrid or remote staff and it mostly works", "next": "working_probe"}, {"label": "We have field staff, not just remote office work", "next": "field_probe"}]}, "lowneed_probe": {"type": "problem", "q": "Any plans to change that — new sites, more flexible working, or field‑based roles coming up?", "options": [{"label": "Yes, that's coming", "next": "result_dev_lowneed"}, {"label": "Possibly, nothing confirmed yet", "next": "result_mid_lowneed"}, {"label": "No, not really", "next": "result_none_lowneed"}]}, "struggle_probe": {"type": "problem", "q": "What's the biggest friction — access to files and systems, security, or just staying connected on calls or Teams?", "options": [{"label": "Security and access are the issue", "next": "result_hot_security"}, {"label": "A bit of everything — access, security and staying connected", "next": "result_mid_struggle"}, {"label": "Just staying connected, more of a productivity thing", "next": "result_hot_productivity"}]}, "working_probe": {"type": "problem", "q": "Good — is that backed by managed security like MFA, endpoint protection and VPN, or more informal?", "options": [{"label": "Fairly informal, no real security layer", "next": "result_dev_working"}, {"label": "Some of it — MFA yes, but not full endpoint protection", "next": "result_mid_working"}, {"label": "Yes, properly secured", "next": "result_none_working"}]}, "field_probe": {"type": "problem", "q": "How do field staff access company systems and data — a secure connection, or ad hoc, like personal hotspots or unsecured Wi‑Fi?", "options": [{"label": "Pretty ad hoc or unsecured", "next": "result_hot_field"}, {"label": "Some field staff have it, others don't", "next": "result_mid_field"}, {"label": "They have proper secure access", "next": "result_none_field"}]}, "result_dev_lowneed": {"result": true, "level": "developing", "title": "Emerging Opportunity — Future Need Identified", "body": "No current need, but change is coming — worth planting the seed now.", "points": ["Ask for a rough timeline on the change", "Offer to revisit closer to the date"], "next": "Nurture — flag for follow‑up nearer the change."}, "result_none_lowneed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Office‑based model with no change on the horizon.", "points": ["Note for future reference"], "next": "Park — low priority today."}, "result_mid_lowneed": {"result": true, "level": "surface", "title": "Possible, Unconfirmed Change", "body": "Nothing concrete yet, but worth a light touchpoint rather than writing it off entirely.", "points": ["Ask what would need to happen for it to become concrete", "Set a light future check‑in rather than a hard follow‑up"], "next": "Very light nurture — check in occasionally, don't push."}, "result_hot_security": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Hybrid Security Gap", "body": "Struggling hybrid workers with security and access friction is a strong, felt pain affecting both productivity and risk.", "points": ["Quantify the productivity impact — time lost, workarounds used", "Position the Mobile Office bundle — MFA, endpoint backup, managed security"], "next": "Strong opportunity — lead with the security and access fix together."}, "result_hot_productivity": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Connectivity Gap", "body": "Hybrid staff struggling to stay connected is a direct productivity cost, easy to quantify.", "points": ["Ask how staff currently reach the office — VPN, nothing, workarounds?", "Position a hosted softphone plus M365 as the connected‑anywhere fix"], "next": "Strong opportunity — quantify lost productivity and propose the bundle."}, "result_mid_struggle": {"result": true, "level": "qualified", "title": "Multiple Compounding Frictions", "body": "When several frictions compound together, the combined impact is usually bigger than any one issue alone — a strong case for a complete fix.", "points": ["Ask which friction hurts the most day to day", "Position the full Mobile Office bundle rather than a single‑point fix"], "next": "Strong opportunity — the combination of issues justifies a complete solution."}, "result_dev_working": {"result": true, "level": "developing", "title": "Emerging Opportunity — Informal Security", "body": "Working today, but without a real security layer — a silent risk.", "points": ["Ask what would happen if a remote device were lost or compromised", "Introduce managed security as protecting what already works"], "next": "Nurture — position as protecting current productivity, not fixing a break."}, "result_none_working": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Hybrid working is functional and secured.", "points": ["Confirm headcount trend for future reference"], "next": "Park — revisit if headcount or hybrid ratio grows."}, "result_mid_working": {"result": true, "level": "developing", "title": "Partial Security Layer", "body": "Partial security is common but leaves specific, identifiable gaps that are usually straightforward to close.", "points": ["Ask specifically what's missing — endpoint protection, VPN, backup?", "Position it as completing an already‑good foundation"], "next": "Upsell — close the specific identified gap."}, "result_hot_field": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Field Staff Security Gap", "body": "Field staff on unsecured connections accessing company data is a real, fixable risk.", "points": ["Ask what data field staff access — customer, financial, operational", "Position secure mobile access plus managed devices as the fix"], "next": "Strong opportunity — lead with the data exposure risk."}, "result_none_field": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Field access is already properly secured.", "points": ["Confirm setup for future reference"], "next": "Park — low priority today."}, "result_mid_field": {"result": true, "level": "developing", "title": "Inconsistent Field Coverage", "body": "Inconsistent coverage usually means the riskiest staff — often the newest or most mobile — are the least protected.", "points": ["Ask which field staff are covered and which aren't", "Standardise coverage across the whole field team"], "next": "Nurture — a consistency gap is often an easy, logical extension."}}, "situationFollowUp": {"q": "How long has hybrid or remote working been set up this way, and is anything changing — more remote hires, new sites, more travel?", "options": [{"label": "Been like this for a while, nothing changing", "note": "Stable hybrid setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — productivity across the wider team, security exposure, or customer-facing work?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate issue."}, {"label": "No, that's the whole picture", "note": "The impact stays contained to what's already been discussed."}]}, "distractorQuestions": {"situation": [{"text": "Everyone can work remotely without any issues, right?", "note": "Closed and leading — makes it easy to just agree rather than reveal anything real."}, {"text": "We've got a great remote-working package, want to hear about it?", "note": "That's pitching before you've found out whether remote work is even a pain point for them."}, {"text": "How's remote working going generally?", "note": "Too vague to surface anything specific worth acting on."}], "problem": [{"text": "Remote staff haven't had any real issues, have they?", "note": "Closed and leading — easy to just say no."}, {"text": "We can sort remote access for you — want a quote?", "note": "Jumps to a quote before confirming there's a real problem."}, {"text": "Anything else going on with remote working?", "note": "Too vague — follow up on what they actually said."}], "implication": [{"text": "That's not really a big deal though, is it?", "note": "That's closed and leading, and it doesn't actually explore the cost or impact — the whole point of an implication question."}, {"text": "So we could sort that for you — want to hear how?", "note": "That jumps straight to the solution before you've actually established what the problem is costing them."}, {"text": "That must be a bit annoying, is it?", "note": "Closed and leading, and it minimises the problem — it invites a shrug instead of exploring what the issue actually costs them."}], "needpayoff": [{"text": "Well, let me know if you ever want to look at it.", "note": "Too passive — a strong need-payoff question invites a real answer and a next step, not an open-ended “whenever.”"}, {"text": "So what budget do you have for this?", "note": "That jumps straight to budget before you've actually confirmed they see the value — budget conversations land better once the value is clear."}, {"text": "Would you be interested in hearing more at some point?", "note": "Too vague and non-committal — it doesn't invite a real answer or move the conversation toward an actual next step."}]}, "primer": {"overview": "Mobile Office is about how staff who aren't at a fixed desk — remote workers, hybrid staff, field teams, people working across multiple sites — actually connect to company systems day to day, and whether that's done securely or through workarounds.", "whyItMatters": "Relevant to any business with staff who work outside a single office — field service, sales teams, multi-site retail or hospitality, or simply a business that shifted to hybrid working and never revisited how it's actually set up.", "keyIndicators": ["Remote or hybrid staff struggling to connect properly to what they need", "Field staff on unsecured connections reaching company data", "No real protection for anyone working outside the office — it's whatever they've cobbled together themselves"], "compellingEvents": ["A shift to more remote or hybrid working that was never properly supported technically", "Field staff complaints about not being able to access what they need on the road", "A security concern about data being accessed over public or home Wi-Fi", "Opening a new site or expanding the field team"], "marketContext": "Hybrid and field-based work is now the norm for a huge share of SMEs, but the technical setup behind it is very often an afterthought — built out of whatever got people working during a disruption, rather than something properly planned.", "valueProp": "Making remote and field work genuinely secure and reliable directly improves productivity, not just security — an easy business case to make.", "exampleQuestions": {"situation": "“How much of the team works outside the office — field, hybrid, multiple sites — and how well does that actually work today?”", "problem": "“Do they ever struggle to access what they need, or end up using workarounds?”", "implication": "“What does that friction actually cost you — lost time, frustrated staff, or security risk?”", "needpayoff": "“If everyone could work securely from anywhere, exactly as if they were at their own desk, would that be worth fixing?”"}, "objections": [{"objection": "“Our remote/hybrid staff manage fine as it is.”", "response": "Ask specifically how they connect today — “managing fine” often means a workaround nobody's flagged as a problem, like using personal Wi-Fi or unmanaged devices."}, {"objection": "“We don't have many people working remotely.”", "response": "Ask if that's likely to grow — even a handful of unmanaged remote connections is a real gap, and it rarely stays a handful for long."}, {"objection": "“Security for remote work sounds complicated to set up.”", "response": "Reassure them it's usually simpler than expected, especially compared to the cost of an actual incident involving a remote device."}]}, "problemFollowUp": {"q": "Is that a one-off, or does it happen regularly with remote working?", "options": [{"label": "Pretty regular, not a one-off", "note": "The issue with remote working is recurring, not a one-time event."}, {"label": "Fairly rare, hasn't happened much", "note": "The issue with remote working has been infrequent so far."}]}, "needpayoffFollowUp": {"q": "Is this something you'd want to move on fairly soon, or more of a future consideration?", "options": [{"label": "Keen to move on this soon", "note": "There's real near-term urgency to act on this."}, {"label": "More of a future consideration", "note": "There's interest, but no immediate urgency to act."}]}}, {"id": "cloud-voice", "name": "Cloud Voice & Collaboration", "short": "Cloud Voice", "icon": "📞", "color": "#0A825A", "blurb": "Are their phones set up sensibly, and ready for the old lines switch-off?", "criteria": ["Phones sit with a different provider than their broadband/access", "Paying twice — separate voice spend they may not even realise", "Still on old ISDN/PSTN lines with no plan before they get switched off"], "implicationQuestions": {"result_hot_separate": "Running two bills and two support lines for something as core as phones and broadband — what does that actually cost you in admin time each month?", "result_mid_separate": "Even if it's manageable, what's the one thing about having it split that annoys you most?", "result_none_separate": "Fair enough — is there anything that would make having them split ever become a problem, like changing offices or providers?", "result_hot_otherprovider": "What's that actually costing you — the money, the time chasing support, or both?", "result_mid_otherprovider": "Are those niggles getting more frequent, or has it always been about the same?", "result_none_otherprovider": "Good to know — is there a renewal date coming up where it'd be worth revisiting?", "result_hot_awareness": "What would consolidating actually solve for you day to day — the billing, the support, or just one less relationship to manage?", "result_mid_awareness": "What's the main thing you'd need to see to feel confident about making a change?", "result_none_awareness": "Understood — is there anything on the horizon, like a lease renewal or office move, that might change that?", "result_hot_bundling": "Roughly what would you say you're paying separately for voice each month, on top of what you already pay us for access?", "result_mid_bundling": "If it turned out you were paying twice, would that be worth a few minutes to check properly?", "result_none_bundling": "Just to be sure — when did you last actually check that on a bill, rather than assume it?", "result_hot_pstn": "If those lines went down before you'd moved, what would that actually cost you — in downtime, or in a scramble to fix it fast?", "result_mid_pstn": "What's stopped you looking into the timeline properly so far — time, or just not knowing where to start?", "result_none_pstn": "Fair enough — if the switch-off date landed sooner than expected, would that change how urgent this feels?"}, "needPayoff": {"separate_probe": "If we brought voice under the same relationship as your access — one bill, one point of contact — would that be worth doing?", "otherprovider_probe": "If your voice sat with the same provider as your access, with no integration gaps, would that solve it?", "awareness_probe": "If we set up a straightforward comparison so you could see exactly what consolidating would look like, would that be a useful next step?", "bundling_probe": "If we could confirm exactly what's bundled and what isn't, and simplify it down to one bill, would that be worth ten minutes of your time?", "pstn_probe": "If we mapped out a straightforward move to VoIP well ahead of the switch-off — same numbers, same features — would now be the time to start planning that?"}, "tree": {"start": {"type": "situation", "q": "Since we already handle your broadband and access here, how are you handling voice and calls at the moment?", "options": [{"label": "Still with a separate provider for phone lines or voice", "next": "separate_probe"}, {"label": "We already have a hosted or VoIP setup, just not through you", "next": "otherprovider_probe"}, {"label": "Honestly, didn't realise you did voice as well", "next": "awareness_probe"}, {"label": "Not sure if voice is bundled with our access or separate", "next": "bundling_probe"}, {"label": "Still running some phone lines on the old ISDN/PSTN network", "next": "pstn_probe"}]}, "separate_probe": {"type": "problem", "q": "How's that working, having access and voice split across two providers — any friction with billing, support, or reliability?", "options": [{"label": "Yes, real friction — different bills, different support lines", "next": "result_hot_separate"}, {"label": "A bit annoying but manageable", "next": "result_mid_separate"}, {"label": "No real issue, works fine as is", "next": "result_none_separate"}]}, "otherprovider_probe": {"type": "problem", "q": "How's that provider working out — any issues with cost, support, or integration with your network?", "options": [{"label": "Yes, issues — cost, support or integration", "next": "result_hot_otherprovider"}, {"label": "A few minor niggles, nothing major", "next": "result_mid_otherprovider"}, {"label": "No complaints", "next": "result_none_otherprovider"}]}, "awareness_probe": {"type": "problem", "q": "No worries — now that you know, is voice something you'd want to explore consolidating with us, or is it not a priority right now?", "options": [{"label": "Yes, keen to explore consolidating", "next": "result_hot_awareness"}, {"label": "Maybe, depends what's involved", "next": "result_mid_awareness"}, {"label": "Not a priority right now", "next": "result_none_awareness"}]}, "bundling_probe": {"type": "problem", "q": "Let's check — do you know if you're paying for voice separately today, or if it's rolled into your access billing?", "options": [{"label": "Pretty sure it's separate, on another bill", "next": "result_hot_bundling"}, {"label": "Not sure, would need to check", "next": "result_mid_bundling"}, {"label": "I think it's already bundled with you", "next": "result_none_bundling"}]}, "result_hot_separate": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Split-Provider Friction", "body": "Access and voice sitting with two different providers is real, everyday friction — one bill, one support line is an easy win to position.", "points": ["Ask how many separate bills or contacts they're juggling for access vs voice", "Position consolidating onto one relationship, one invoice"], "next": "Strong opportunity — lead with consolidation of billing and support."}, "result_mid_separate": {"result": true, "level": "developing", "title": "Emerging Opportunity — Manageable Friction", "body": "Not painful enough to force a change yet, but worth surfacing the hidden cost of running two vendors.", "points": ["Ask how much admin time goes into managing two separate relationships", "Introduce consolidation as simplification, not urgency"], "next": "Nurture — quantify the hidden admin cost of two vendors."}, "result_none_separate": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Split provider setup works fine for them today — not a live pain.", "points": ["Note their voice provider and contract length for future reference"], "next": "Park — revisit near their voice contract renewal."}, "result_hot_otherprovider": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Competitor Voice Pain", "body": "Real issues with their current voice provider is a strong displacement opportunity — and one you can fold straight into their existing access relationship.", "points": ["Get specifics — cost, support responsiveness, integration with their network", "Position a single-vendor upgrade, not just a voice swap"], "next": "Displacement play — anchor to consolidating onto the relationship they already trust."}, "result_mid_otherprovider": {"result": true, "level": "developing", "title": "Emerging Opportunity — Minor Provider Niggles", "body": "Small issues, not painful enough to switch on their own — but worth linking to the value of one vendor.", "points": ["Ask if those niggles are getting worse or more frequent", "Mention consolidation as a bonus reason to switch, not the only reason"], "next": "Nurture — pair the niggles with the consolidation angle."}, "result_none_otherprovider": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Happy with their current voice provider — not a live opportunity today.", "points": ["Note the incumbent and contract length for future reference"], "next": "Park — revisit near their voice contract renewal."}, "result_hot_awareness": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Ready to Consolidate", "body": "An access customer who's keen to explore consolidating voice is about as warm as this gets — no incumbent objection to overcome, just execution.", "points": ["Map out their current voice setup so you can show a clean like-for-like", "Move quickly — enthusiasm on a first mention fades if not followed up"], "next": "Fast-moving opportunity — propose consolidation while the interest is fresh."}, "result_mid_awareness": {"result": true, "level": "developing", "title": "Emerging Opportunity — Open But Uncommitted", "body": "Interested in principle, but needs to see what's actually involved before committing.", "points": ["Offer a simple, low-commitment comparison of their current setup vs a consolidated platform", "Address any concern about disruption during a switch"], "next": "Nurture — remove the unknowns with a simple comparison."}, "result_none_awareness": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Not a priority for them right now, even with awareness raised.", "points": ["Note that they're now aware you offer voice, for future reference"], "next": "Park — low priority today, but awareness has been planted."}, "result_hot_bundling": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Separate Voice Spend Identified", "body": "Confirmed separate voice spend sitting outside their access relationship with us is a clear, quantifiable consolidation opportunity.", "points": ["Ask roughly what they're paying separately for voice today", "Show the value of folding that spend into a single relationship"], "next": "Strong opportunity — quantify the separate spend and propose consolidation."}, "result_mid_bundling": {"result": true, "level": "developing", "title": "Emerging Opportunity — Needs Billing Clarity", "body": "Genuine uncertainty about their own billing is a natural entry point for a quick account review.", "points": ["Offer to check their account together to clarify what's bundled and what isn't", "Use the review as the way into the wider voice conversation"], "next": "Nurture — offer a quick billing review to clarify the picture."}, "result_none_bundling": {"result": true, "level": "none", "title": "No Immediate Opportunity — Believes Already Bundled", "body": "They believe voice is already bundled with their access — confirm this is accurate before moving on.", "points": ["Double-check their account to confirm whether voice is genuinely included", "If it turns out it isn't, this becomes a strong opportunity — worth a quick verify"], "next": "Verify their account — this may actually be a hidden opportunity if their belief is wrong."}, "pstn_probe": {"type": "problem", "q": "How are those lines treating you day to day — any issues with reliability or cost, or is the switch-off deadline on your radar at all?", "options": [{"label": "Yes — already having issues, or worried about the deadline", "next": "result_hot_pstn"}, {"label": "A bit concerned but haven't looked into it properly", "next": "result_mid_pstn"}, {"label": "No concerns, working fine as is", "next": "result_none_pstn"}]}, "result_hot_pstn": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Legacy Line Switch-Off Risk", "body": "Live pain or a looming deadline on ISDN/PSTN lines is about as urgent as this gets — the switch-off isn't optional, so this is a when-not-if conversation.", "points": ["Confirm which lines are still ISDN/PSTN and roughly how many", "Position VoIP migration as protecting continuity, not just a nice-to-have upgrade"], "next": "Urgent opportunity — the network switch-off gives this a real deadline to work against."}, "result_mid_pstn": {"result": true, "level": "developing", "title": "Emerging Opportunity — Aware But Not Yet Acting", "body": "Some awareness of the switch-off but no plan yet — a good moment to bring clarity before it becomes urgent.", "points": ["Explain the switch-off timeline in plain terms, not just as a sales pitch", "Offer to map out exactly which lines are affected and what moving to VoIP would look like"], "next": "Nurture — educate on the timeline and offer a simple migration map."}, "result_none_pstn": {"result": true, "level": "none", "title": "No Immediate Opportunity — Unaware of Switch-Off", "body": "No concerns today, but if they're unaware the lines are being switched off industry-wide, that's a gap worth closing gently.", "points": ["Flag that the ISDN/PSTN switch-off is happening across the industry, not specific to us", "Note the lines for a proactive follow-up before it becomes urgent"], "next": "Park — but flag for proactive outreach ahead of the switch-off."}}, "situationFollowUp": {"q": "How long has voice been set up this way, and is there anything on the horizon — a house move, more staff, a new provider contract ending — that might change that?", "options": [{"label": "It's been like this for a long time, no changes on the horizon", "note": "Long-standing setup, no obvious change trigger on the horizon."}, {"label": "Something's coming up that could change things", "note": "There's a change coming that could be a natural trigger point."}]}, "implicationFollowUp": {"q": "Does this affect anything beyond what you've mentioned — customer experience, staff frustration, or missed opportunities elsewhere?", "options": [{"label": "Yes, it touches other things too", "note": "The impact reaches beyond just the immediate issue mentioned."}, {"label": "No, that's really the whole picture", "note": "The impact is fully contained to what's already been said."}]}, "distractorQuestions": {"situation": [{"text": "Your phone system's working fine, isn't it?", "note": "Closed and leading — easy for them to just say yes."}, {"text": "We've got a great VoIP deal on right now, want to hear about it?", "note": "That's pitching before you've established whether there's a real problem with their current setup."}, {"text": "How are the phones going generally?", "note": "Too vague to point at anything specific."}], "problem": [{"text": "You haven't had any issues with the phone system, have you?", "note": "Closed and leading — invites a quick no."}, {"text": "We can sort your phone system — want a quote?", "note": "Jumps to a quote before confirming a genuine problem."}, {"text": "Anything else going on with the phones?", "note": "Too vague — build on what they just told you."}], "implication": [{"text": "That's not really a big deal though, is it?", "note": "That's closed and leading, and it doesn't actually explore the cost or impact — the whole point of an implication question."}, {"text": "So we could sort that for you — want to hear how?", "note": "That jumps straight to the solution before you've actually established what the problem is costing them."}, {"text": "That must be a bit annoying, is it?", "note": "Closed and leading, and it minimises the problem — it invites a shrug instead of exploring what the issue actually costs them."}], "needpayoff": [{"text": "Well, let me know if you ever want to look at it.", "note": "Too passive — a strong need-payoff question invites a real answer and a next step, not an open-ended “whenever.”"}, {"text": "So what budget do you have for this?", "note": "That jumps straight to budget before you've actually confirmed they see the value — budget conversations land better once the value is clear."}, {"text": "Would you be interested in hearing more at some point?", "note": "Too vague and non-committal — it doesn't invite a real answer or move the conversation toward an actual next step."}]}, "primer": {"overview": "Cloud Voice & Collaboration covers how a business handles phone calls and voice communication — whether that's through a separate old-fashioned phone system, or a modern VoIP (Voice over Internet Protocol) setup that runs over the same connection as everything else. It also covers the industry-wide switch-off of old ISDN/PSTN phone lines, which is forcing this conversation for a lot of businesses whether they've thought about it or not.", "whyItMatters": "Relevant to almost every SME, since almost every business has phones — but especially urgent for anyone still on old ISDN/PSTN lines, since those are being switched off industry-wide and businesses that haven't planned for it risk simply losing the ability to make and receive calls.", "keyIndicators": ["Phones sit with a different provider than their broadband/access, meaning two separate relationships to manage", "Paying twice — separate voice spend they may not even realise is disconnected from their other costs", "Still on old ISDN/PSTN lines with no plan before they get switched off"], "compellingEvents": ["The industry-wide ISDN/PSTN switch-off — a genuine deadline, not a sales tactic", "A phone contract renewal, which is the natural moment to bundle voice with everything else", "An outage or reliability issue with the current phone setup", "Opening a new site and needing to decide how phones work there"], "marketContext": "The industry-wide move away from old copper ISDN/PSTN lines toward VoIP is a real, externally-driven deadline — not something invented for a sales pitch — and a lot of SMEs are unaware it affects them until their lines are affected.", "valueProp": "Moving to VoIP ahead of the switch-off, on your own timeline, keeps the same numbers and features intact — far better than being forced to scramble once the old lines actually go dead.", "exampleQuestions": {"situation": "“Since we already handle your broadband and access here, how are you handling voice and calls at the moment?”", "problem": "“Are you still on the old ISDN or PSTN lines, and have you looked into the switch-off timeline at all?”", "implication": "“If those lines went down before you'd moved, what would that actually mean — missed calls, lost business?”", "needpayoff": "“If we mapped out a straightforward move to VoIP well ahead of the switch-off, would now be the time to plan it?”"}, "objections": [{"objection": "“Our phones work fine as they are.”", "response": "Ask if they're aware of the ISDN/PSTN switch-off timeline — “working fine today” doesn't mean they're not on borrowed time if they're still on old lines."}, {"objection": "“We don't want to change our phone numbers.”", "response": "Reassure them numbers carry over in a VoIP migration — this is a common misconception worth clearing up early."}, {"objection": "“We already have a phone provider.”", "response": "Ask how that's working out, and note that bundling voice with their existing connectivity often simplifies billing and support, not just switches provider for its own sake."}]}, "problemFollowUp": {"q": "Is that a one-off, or does it happen regularly with the phone system?", "options": [{"label": "Pretty regular, not a one-off", "note": "The issue with the phone system is recurring, not a one-time event."}, {"label": "Fairly rare, hasn't happened much", "note": "The issue with the phone system has been infrequent so far."}]}, "needpayoffFollowUp": {"q": "Is this something you'd want to move on fairly soon, or more of a future consideration?", "options": [{"label": "Keen to move on this soon", "note": "There's real near-term urgency to act on this."}, {"label": "More of a future consideration", "note": "There's interest, but no immediate urgency to act."}]}}, {"id": "cloud-infrastructure", "name": "Cloud, Backup & Resilience", "short": "Cloud & Resilience", "icon": "☁️", "color": "#3B6FA0", "blurb": "Where does their stuff actually live, and would it survive a bad day?", "criteria": ["Old physical servers on-site with no plan to move them", "Using cloud services already, but nobody's really managing it", "Backups exist, but have never actually been tested — or don't exist at all"], "implicationQuestions": {"result_hot_onprem": "If that hardware failed before you'd planned for it, what would that actually mean — downtime, cost, or both?", "result_mid_onprem": "What's stopped you from properly planning that migration so far — time, cost, or just not knowing where to start?", "result_none_onprem": "Fair enough — when that hardware does eventually need replacing, is cloud something you'd actually consider, or straight like-for-like?", "result_hot_partial": "What does not having full oversight actually cost you — wasted spend, security gaps, or just not knowing what's running?", "result_mid_partial": "Is that likely to get worse as you use more cloud services, or stay about the same?", "result_none_partial": "Good to know — is there anyone actively keeping an eye on that as you grow?", "result_hot_vdi": "What does that friction actually cost you — lost time, frustrated staff, or workarounds that aren't secure?", "result_mid_vdi": "Is that a growing need as more people work flexibly, or fairly stable for now?", "result_none_vdi": "Does that cover everyone who needs it, or just some of the team?", "result_hot_awareness": "What would having that clarity actually let you do differently — plan a budget, spot waste, or something else?", "result_mid_awareness": "What would it take to make getting that picture an actual priority?", "result_none_awareness": "Fair enough — is there anything on the horizon, like growth or a new hire, that might change that confidence?", "bk_result_dev_immutable": "If ransomware got onto that on-site copy too, what would recovery actually look like — and how long would it take?", "bk_result_mid_immutable": "If that off-site copy could still be reached and encrypted, what would that mean for your recovery timeline?", "bk_result_none_solid": "Good — when was the last time you actually tested a full restore from it, not just confirmed it runs?", "bk_result_hot_untested": "Beyond the data itself, what would a failed restore cost you in downtime, reputation, or compliance?", "bk_result_mid_untested": "If the next test were a full system restore instead of a single file, how confident are you it would go the same way?", "bk_result_warm_untested": "Is there any data at all that, if you lost it for good, would actually hurt?", "bk_result_hot_nobackup": "If you lost everything tomorrow — customer records, financials, the lot — how long could the business realistically survive without it?", "bk_result_mid_gap": "For whatever's not covered, what's actually on those systems — and what would it cost to lose them?", "bk_result_hot_unowned": "If a backup job silently failed for a month, who would be the one to notice — and how?", "bk_result_hot_incident": "What did that actually cost you — the time it took, the work redone, or the trust it cost with customers?", "bk_result_mid_incident": "If that near miss hadn't been caught in time, what would the last month have looked like instead?", "bk_result_warm_incident": "Even though you got through it, what did that stress and slow recovery cost the team in the meantime?"}, "needPayoff": {"onprem_probe": "If we mapped a migration to cloud infrastructure that removed the ageing hardware risk entirely, would that be worth planning now, before it becomes urgent?", "partial_probe": "If everything sat under one properly managed cloud environment, with full visibility and control, would that be worth doing?", "vdi_probe": "If your team could securely access a full virtual desktop from anywhere, exactly as if they were at their own PC, would that solve it?", "awareness_probe": "If we mapped out exactly what's running where today, and where cloud could genuinely help, would that be a useful next step?", "bk_testing_probe": "If your backups were fully immutable and off-site, would that finally put this to rest?", "bk_untested_probe": "If we proved a full restore works, on record, would that give you the confidence you're missing?", "bk_gap_probe": "If there was a proper backup in place from day one, what would that be worth against the risk you're carrying now?", "bk_incident_probe": "If we made sure that exact scenario couldn't happen again, how much would that change your risk posture?"}, "tree": {"start": {"type": "situation", "q": "How would you describe where your business systems actually run today — your own physical servers, cloud, or a bit of both?", "options": [{"label": "We still run our own physical servers or infrastructure on-site", "next": "onprem_probe"}, {"label": "We use some cloud services already, but it's a bit ad-hoc — nothing formally managed", "next": "partial_probe"}, {"label": "Staff need to work from a full desktop or specific apps remotely, not just files", "next": "vdi_probe"}, {"label": "Honestly, not sure what's running on our own hardware versus in the cloud", "next": "awareness_probe"}, {"label": "Very confident — we back up regularly and test it", "next": "bk_testing_probe"}, {"label": "We back up, but haven't actually tested a restore", "next": "bk_untested_probe"}, {"label": "Not confident at all / not sure what's covered", "next": "bk_gap_probe"}, {"label": "We've actually had data loss or a ransomware scare", "next": "bk_incident_probe"}]}, "onprem_probe": {"type": "problem", "q": "How's that ageing on-site kit treating you — getting harder to maintain, due a refresh, or running fine for now?", "options": [{"label": "Getting old and hard to maintain, a refresh is looming", "next": "result_hot_onprem"}, {"label": "It's manageable for now, but we know it won't last forever", "next": "result_mid_onprem"}, {"label": "Fairly new or running fine, no rush", "next": "result_none_onprem"}]}, "partial_probe": {"type": "problem", "q": "What's that patchwork actually costing you — in cost, control, or just knowing what's running where?", "options": [{"label": "Real cost or control issues, nobody has full oversight", "next": "result_hot_partial"}, {"label": "A few inefficiencies but nothing major", "next": "result_mid_partial"}, {"label": "Working fine as is", "next": "result_none_partial"}]}, "vdi_probe": {"type": "problem", "q": "How are they doing that today — remoting into a physical PC, a clunky workaround, or nothing formal at all?", "options": [{"label": "A clunky workaround or nothing formal — real friction", "next": "result_hot_vdi"}, {"label": "Works, but not great", "next": "result_mid_vdi"}, {"label": "Already have a proper virtual desktop or remote app setup", "next": "result_none_vdi"}]}, "awareness_probe": {"type": "problem", "q": "Would it be useful to get a clear picture of what's running where today, and whether it's set up sensibly?", "options": [{"label": "Yes, that would genuinely help", "next": "result_hot_awareness"}, {"label": "Maybe, not a priority right now", "next": "result_mid_awareness"}, {"label": "We're confident we already know", "next": "result_none_awareness"}]}, "result_hot_onprem": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Ageing Hardware, Migration Window Open", "body": "Ageing on-site infrastructure with a looming refresh is the clearest possible moment to move to cloud instead of buying like-for-like.", "points": ["Ask what's actually running on it and how business-critical it is", "Position Azure migration as replacing the refresh, not adding a project on top of it"], "next": "Strong opportunity — propose migration in place of a like-for-like hardware refresh."}, "result_mid_onprem": {"result": true, "level": "developing", "title": "Emerging Opportunity — Aware Refresh Is Coming", "body": "Some awareness that a refresh is coming, but no plan yet — worth bringing clarity before it becomes urgent.", "points": ["Get a rough timeline for when a decision would need to be made", "Offer to map out what a cloud migration would actually look like versus a straight refresh"], "next": "Nurture — offer a like-for-like versus migration comparison ahead of the decision."}, "result_none_onprem": {"result": true, "level": "none", "title": "No Immediate Opportunity — Recently Refreshed", "body": "Recently refreshed or running fine — not a live opportunity today.", "points": ["Note the refresh date for a follow-up nearer their next cycle"], "next": "Park — revisit near their next hardware refresh cycle."}, "result_hot_partial": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Unmanaged Cloud Sprawl", "body": "Real cost or control issues with no one owning it properly is a strong, fixable opportunity to bring order and savings.", "points": ["Ask roughly how many cloud services are in use and who owns each one", "Position a proper Azure environment as consolidating cost and control, not adding another tool"], "next": "Strong opportunity — propose consolidating onto one properly managed environment."}, "result_mid_partial": {"result": true, "level": "developing", "title": "Emerging Opportunity — Minor Inefficiencies", "body": "Not painful enough to force a change yet, but worth surfacing the hidden cost of an ad-hoc setup.", "points": ["Ask if those inefficiencies are getting more noticeable as they grow", "Introduce proper management as tidying up, not urgency"], "next": "Nurture — quantify the hidden cost of the ad-hoc setup."}, "result_none_partial": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Working fine as is today — not a live pain.", "points": ["Note their current setup for future reference"], "next": "Park — revisit if their cloud usage grows significantly."}, "result_hot_vdi": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Proper Remote Desktop Access", "body": "Real friction getting a full desktop or specific apps remotely is a clean, well-understood problem that virtual desktop solves directly.", "points": ["Ask exactly what the workaround looks like today and how often it's used", "Position Azure Virtual Desktop as replacing the workaround, not adding new complexity"], "next": "Strong opportunity — propose Azure Virtual Desktop to replace the workaround."}, "result_mid_vdi": {"result": true, "level": "developing", "title": "Emerging Opportunity — Works, Not Great", "body": "A working-but-imperfect setup often means staff quietly working around it — worth checking how well it actually holds up.", "points": ["Ask if staff ever avoid using it because it's slow or awkward", "Position virtual desktop as improving experience, not just fixing a problem"], "next": "Nurture — pair the experience angle with the security case."}, "result_none_vdi": {"result": true, "level": "none", "title": "No Immediate Opportunity — Already Covered", "body": "Already has a proper virtual desktop or remote app setup — not a live gap today.", "points": ["Note what they use for future reference"], "next": "Park — revisit if their setup changes or scales."}, "result_hot_awareness": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Wants Clarity", "body": "A genuine want for visibility into where systems run is a strong opening for a straightforward infrastructure review.", "points": ["Offer a simple, low-commitment review of what's running where today", "Use the review as the way into the wider cloud conversation"], "next": "Strong opportunity — offer a quick infrastructure review as the next step."}, "result_mid_awareness": {"result": true, "level": "developing", "title": "Emerging Opportunity — Not Yet a Priority", "body": "Open to the idea but not urgent — worth staying lightly in touch rather than pushing.", "points": ["Ask what would need to change for this to become a priority", "Offer the review as a no-obligation starting point whenever it does"], "next": "Very light nurture — stay visible for when it becomes a priority."}, "result_none_awareness": {"result": true, "level": "none", "title": "No Immediate Opportunity — Confident Already", "body": "Confident they already know the picture — worth a light double-check rather than pushing further.", "points": ["Note their confidence level for a future light-touch check-in"], "next": "Park — low priority today, but worth a light check-in later."}, "bk_testing_probe": {"type": "problem", "q": "Great — is that backup immutable, so it's ransomware‑proof, and does it include an off‑site or cloud copy?", "options": [{"label": "Not sure it's immutable, or it's on‑site only", "next": "bk_result_dev_immutable"}, {"label": "We have an off‑site copy but I'm not sure about immutability", "next": "bk_result_mid_immutable"}, {"label": "Yes, immutable and off‑site", "next": "bk_result_none_solid"}]}, "bk_untested_probe": {"type": "problem", "q": "What would happen to the business if a restore failed and you lost, say, a week of data?", "options": [{"label": "That would be seriously damaging", "next": "bk_result_hot_untested"}, {"label": "We've tested small file restores, just not a full system restore", "next": "bk_result_mid_untested"}, {"label": "Manageable — we don't rely on it heavily", "next": "bk_result_warm_untested"}]}, "bk_gap_probe": {"type": "problem", "q": "Is that because there's no formal backup, or because nobody's really sure what's covered?", "options": [{"label": "No formal backup in place", "next": "bk_result_hot_nobackup"}, {"label": "Backup runs on some systems but not others", "next": "bk_result_mid_gap"}, {"label": "Backup exists but nobody really owns it", "next": "bk_result_hot_unowned"}]}, "bk_incident_probe": {"type": "problem", "q": "What happened, and how long did it take to recover?", "options": [{"label": "Lost data permanently, or it took days to recover", "next": "bk_result_hot_incident"}, {"label": "It was a near miss — caught before real damage was done", "next": "bk_result_mid_incident"}, {"label": "Recovered OK, but it was stressful and slow", "next": "bk_result_warm_incident"}]}, "bk_result_dev_immutable": {"result": true, "level": "developing", "title": "Emerging Opportunity — Immutability Gap", "body": "Backups exist but may not survive a ransomware attack — a real, currently unfelt risk.", "points": ["Ask if backups sit on the same network as production", "Introduce the Immutable tier — MFA, encryption, restricted admin access"], "next": "Position as risk reduction, not urgency — good for a QBR or renewal conversation."}, "bk_result_none_solid": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Solid backup posture already in place.", "points": ["Confirm RPO/RTO and who tests the restores"], "next": "Park — check in at renewal or if their infrastructure changes."}, "bk_result_mid_immutable": {"result": true, "level": "developing", "title": "Off‑Site But Not Immutable", "body": "An off‑site copy is good practice, but without immutability, a determined ransomware attack could still reach it.", "points": ["Ask if backup credentials are separated from day‑to‑day admin access", "Introduce immutability as closing the one remaining gap"], "next": "Upsell — position immutability as the final piece, not a rebuild."}, "bk_result_hot_untested": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Untested Recovery", "body": "An untested restore is a false sense of security — high stakes if it fails, and they already know it.", "points": ["Offer a test restore as proof of concept", "Position quarterly restore validation as standard practice"], "next": "Strong opportunity — lead with a free or low‑cost test restore to prove the gap."}, "bk_result_warm_untested": {"result": true, "level": "developing", "title": "Emerging Opportunity — Low Perceived Risk", "body": "They're not worried, so there's no urgency yet — this needs a trigger.", "points": ["Ask what data would be hardest to lose — customer records, financials?", "Reframe around a scenario that matters to them specifically"], "next": "Nurture — needs a compelling 'what if' before it moves."}, "bk_result_mid_untested": {"result": true, "level": "developing", "title": "Partially Tested", "body": "Partial testing is better than none, but a full‑system restore is a very different test than restoring a single file.", "points": ["Ask when the last full‑system test was, if ever", "Offer a full restore test as the definitive proof point"], "next": "Nurture — offer a full‑scope restore test to close the confidence gap."}, "bk_result_hot_nobackup": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Backup At All", "body": "No formal backup is one of the highest‑risk gaps in the entire portfolio.", "points": ["Quantify what a full data loss would actually cost them", "Lead with the Essential tier — local‑first backup, automatic endpoint coverage"], "next": "Urgent — this is a foundational gap, propose immediately."}, "bk_result_hot_unowned": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Unowned Backup", "body": "Backup exists but nobody's accountable — it's likely to fail silently exactly when it's needed most.", "points": ["Ask who would notice if a backup job failed", "Position a managed backup service as giving clear ownership plus monthly restore checks"], "next": "Qualified on the accountability gap — propose managed backup with reporting."}, "bk_result_mid_gap": {"result": true, "level": "developing", "title": "Inconsistent Coverage", "body": "Partial coverage means some critical data may be protected while other systems are completely exposed.", "points": ["Ask which systems are covered and which aren't", "Map out the gap systematically rather than assuming"], "next": "Strong nurture — a coverage audit often reveals more risk than expected."}, "bk_result_hot_incident": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Real Data Loss Event", "body": "A genuine data loss event is as strong a trigger as they come.", "points": ["Ask what's changed since then", "Use the incident to justify the DR tier — RPO/RTO‑led runbooks"], "next": "Fast‑track — same‑quarter opportunity, lead with the DR tier."}, "bk_result_warm_incident": {"result": true, "level": "developing", "title": "Emerging Opportunity — Recovered but Slow", "body": "They got through it, so urgency has faded — needs re‑anchoring to the stress it caused.", "points": ["Ask how long it took and what it cost in staff time", "Reintroduce the pain — 'what if it happened again tomorrow?'"], "next": "Nurture — reconnect to the memory of the incident."}, "bk_result_mid_incident": {"result": true, "level": "developing", "title": "Near Miss", "body": "A near miss is a free warning — the risk is real, but there's no fresh wound driving urgency the way an actual loss would.", "points": ["Ask what would have happened if it hadn't been caught in time", "Use the near miss as a preview of a worse outcome"], "next": "Nurture — use the near miss as a cautionary trigger, not a closed chapter."}}, "situationFollowUp": {"q": "How long has it been set up this way, and is anything on the horizon that might change that — growth, a lease renewal, new hires?", "options": [{"label": "Been like this a while, nothing changing", "note": "Long-standing infrastructure setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — cost control, compliance, or trust if something went wrong?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact extends beyond the immediate issue into cost, compliance or trust."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}, "distractorQuestions": {"situation": [{"text": "Your backups and infrastructure are all sorted, aren't they?", "note": "Closed and leading — invites a quick yes rather than a genuine answer."}, {"text": "We've got a great cloud migration deal on, want to hear about it?", "note": "That's pitching before you've confirmed there's actually a gap to fix."}, {"text": "How's your IT infrastructure going generally?", "note": "Too vague to surface anything specific worth exploring."}], "problem": [{"text": "Your backups and infrastructure haven't had any issues, have they?", "note": "Closed and leading — easy to just say no."}, {"text": "We can sort your infrastructure — want a quote?", "note": "Jumps to a quote before confirming there's a real gap."}, {"text": "Anything else going on with your systems?", "note": "Too vague — follow up on what they specifically said."}], "implication": [{"text": "That's not really a big deal though, is it?", "note": "That's closed and leading, and it doesn't actually explore the cost or impact — the whole point of an implication question."}, {"text": "So we could sort that for you — want to hear how?", "note": "That jumps straight to the solution before you've actually established what the problem is costing them."}, {"text": "That must be a bit annoying, is it?", "note": "Closed and leading, and it minimises the problem — it invites a shrug instead of exploring what the issue actually costs them."}], "needpayoff": [{"text": "Well, let me know if you ever want to look at it.", "note": "Too passive — a strong need-payoff question invites a real answer and a next step, not an open-ended “whenever.”"}, {"text": "So what budget do you have for this?", "note": "That jumps straight to budget before you've actually confirmed they see the value — budget conversations land better once the value is clear."}, {"text": "Would you be interested in hearing more at some point?", "note": "Too vague and non-committal — it doesn't invite a real answer or move the conversation toward an actual next step."}]}, "primer": {"overview": "Cloud, Backup & Resilience covers where a business's actual systems and data live — on physical servers on-site, in the cloud (Azure), or some mix — plus whether there's a tested, reliable backup and disaster recovery plan in case something goes wrong. It includes virtual desktop (letting staff access a full desktop remotely) and virtualisation more broadly.", "whyItMatters": "Relevant to any business running its own physical servers that are ageing, anyone using cloud services in an ad-hoc, unmanaged way, or anyone who's never actually tested whether their backups would work if they needed them.", "keyIndicators": ["Old physical servers on-site with no plan to move them", "Using cloud services already, but nobody's really managing it properly", "Backups exist, but have never actually been tested — or don't exist at all"], "compellingEvents": ["Ageing on-site hardware approaching a refresh point — the natural moment to consider cloud instead of like-for-like replacement", "A near-miss or actual data loss incident that exposed backups were never properly tested", "Growing cloud usage that's become genuinely hard to track or control", "Staff needing full remote desktop access rather than just files"], "marketContext": "Many SMEs have backups that technically exist but have never once been tested by actually restoring from them — which means, in practice, nobody actually knows if they'd work when it mattered most.", "valueProp": "A migration timed around a hardware refresh removes ongoing risk without adding a separate project, and a genuinely tested backup plan is the difference between a bad day and a business-ending one.", "exampleQuestions": {"situation": "“How would you describe where your business systems actually run today — your own physical servers, cloud, or a bit of both?”", "problem": "“Has your backup ever actually been tested — restoring something for real, not just assuming it's running?”", "implication": "“If you lost access to that data tomorrow, what would that actually mean for the business?”", "needpayoff": "“If we made sure that was properly backed up and tested, would that be worth sorting out?”"}, "objections": [{"objection": "“Our servers still work, why would we move them?”", "response": "Ask how old the hardware is and what the refresh plan is — “still working” and “not due to fail soon” aren't guaranteed to be the same thing."}, {"objection": "“We've got backups, we're covered.”", "response": "Ask when they last actually tested a restore — a backup that's never been tested is an assumption, not a guarantee."}, {"objection": "“Migrating to the cloud sounds like a big project.”", "response": "Acknowledge that, then explain it's often timed around a hardware refresh they were going to do anyway — not an extra project on top."}]}, "problemFollowUp": {"q": "Is that a one-off, or does it happen regularly with your infrastructure?", "options": [{"label": "Pretty regular, not a one-off", "note": "The issue with your infrastructure is recurring, not a one-time event."}, {"label": "Fairly rare, hasn't happened much", "note": "The issue with your infrastructure has been infrequent so far."}]}, "needpayoffFollowUp": {"q": "Is this something you'd want to move on fairly soon, or more of a future consideration?", "options": [{"label": "Keen to move on this soon", "note": "There's real near-term urgency to act on this."}, {"label": "More of a future consideration", "note": "There's interest, but no immediate urgency to act."}]}}, {"id": "support-services", "name": "Support & Service Management", "short": "Support", "icon": "🎧", "color": "#0A825A", "blurb": "When something breaks, do they know exactly who to call?", "criteria": ["No clear process for who fixes what when it breaks", "No agreed response time — just whenever someone gets to it", "One stretched person or team trying to cover everything"], "implicationQuestions": {"result_hot_chaotic": "Across a year, what does that chaos actually add up to — in lost time, lost trade, or both?", "result_mid_chaotic": "What happens on the days the right person isn't around?", "result_warm_chaotic": "How much staff time would you guess goes into chasing things down each month?", "result_hot_slow": "What's the real cost of not knowing how long something will take to get fixed?", "result_mid_slow": "Which one — the resourcing or the process — causes you more grief day to day?", "result_warm_slow": "Is it getting more frequent as things get busier, or has it stayed about the same?", "result_dev_healthy": "How much time goes into just figuring out which provider to call for a given issue?", "result_mid_healthy": "What are those remaining separate items, and how much hassle do they cause?", "result_hot_internal": "If that internal capacity actually broke down, what would the business lose in the meantime?", "result_mid_internal": "What's the specific thing you're watching for that would tell you it's become a problem?", "result_warm_internal": "What would need to change for that to stop being sustainable?", "result_none_healthy": "Good — is that relationship reviewed periodically, or is it just working well by habit?"}, "needPayoff": {"chaotic_probe": "If there was one number to call with a guaranteed response, what would that be worth?", "slow_probe": "If every issue had a clear SLA and escalation path, would that remove the uncertainty?", "healthy_probe": "If everything ran through a single point of contact, would that be worth simplifying, even if support is already decent?", "internal_probe": "If your team got that time back for higher‑value work, what would that be worth to the business?"}, "tree": {"start": {"type": "situation", "q": "When something goes wrong today — network, phones, backup, anything — what actually happens? Who do you call, and how fast is it usually sorted?", "options": [{"label": "We don't have a clear support process — it's a bit chaotic", "next": "chaotic_probe"}, {"label": "We have support, but it's slow or inconsistent", "next": "slow_probe"}, {"label": "We have decent support already", "next": "healthy_probe"}, {"label": "We manage most things ourselves internally", "next": "internal_probe"}]}, "chaotic_probe": {"type": "problem", "q": "What's the impact when that happens — how long does it typically take to get sorted, and what does that cost the business?", "options": [{"label": "Takes a long time, real business impact", "next": "result_hot_chaotic"}, {"label": "It varies a lot depending on who's around to help", "next": "result_mid_chaotic"}, {"label": "Usually sorted eventually, just messy", "next": "result_warm_chaotic"}]}, "slow_probe": {"type": "problem", "q": "Is that a resourcing issue on their end, unclear escalation paths, or something else?", "options": [{"label": "Unclear escalation, no real SLA", "next": "result_hot_slow"}, {"label": "A bit of both, if I'm honest", "next": "result_mid_slow"}, {"label": "Just occasionally slow, not a big deal", "next": "result_warm_slow"}]}, "healthy_probe": {"type": "problem", "q": "Good — is that a single point of contact across everything, network, voice, backup, security, or different providers for different things?", "options": [{"label": "Different providers for different things", "next": "result_dev_healthy"}, {"label": "Mostly one contact, but a couple of things sit elsewhere", "next": "result_mid_healthy"}, {"label": "Yes, single point of contact for everything", "next": "result_none_healthy"}]}, "internal_probe": {"type": "problem", "q": "As you grow, is that still sustainable, or is it starting to stretch the team thin?", "options": [{"label": "Starting to stretch us thin", "next": "result_hot_internal"}, {"label": "Sustainable for now, but we're keeping an eye on it", "next": "result_mid_internal"}, {"label": "Still sustainable for now", "next": "result_warm_internal"}]}, "result_hot_chaotic": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Support Structure", "body": "No clear support process with real business impact is a strong, easy‑to‑justify opportunity.", "points": ["Quantify the cost of a typical incident — time, lost trade", "Position a single point of contact — one support route and agreed escalation path"], "next": "Strong opportunity — lead with a defined support model and SLA."}, "result_warm_chaotic": {"result": true, "level": "developing", "title": "Emerging Opportunity — Messy but Functional", "body": "Gets resolved eventually — needs a cost story to create urgency.", "points": ["Ask how much staff time gets spent chasing issues", "Reframe the 'eventually' as a hidden cost"], "next": "Nurture — quantify the hidden cost of the messy process."}, "result_mid_chaotic": {"result": true, "level": "developing", "title": "Inconsistent, Person‑Dependent", "body": "Relying on specific people being available is a fragile setup — it works until the right person is unavailable.", "points": ["Ask what happens when that key person is out or unreachable", "Position a defined process as removing single points of failure"], "next": "Nurture — highlight the risk of depending on specific individuals."}, "result_hot_slow": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Clear SLA", "body": "Unclear escalation and no SLA is a real accountability gap.", "points": ["Ask what they'd want a proper SLA to guarantee", "Position agreed escalation paths and reporting as the fix"], "next": "Strong opportunity — propose a clear SLA and escalation model."}, "result_warm_slow": {"result": true, "level": "developing", "title": "Emerging Opportunity — Occasional Friction", "body": "Not painful enough yet to force a change.", "points": ["Ask if it's getting more frequent as they grow", "Keep warm for a future trigger"], "next": "Nurture — monitor for increasing frequency."}, "result_mid_slow": {"result": true, "level": "developing", "title": "Combined Resourcing and Process Gap", "body": "When both resourcing and process are weak, fixing just one won't fully solve it — worth addressing together.", "points": ["Ask which one causes more frustration day to day", "Position a managed model as solving both at once"], "next": "Strong nurture — a combined gap often justifies a combined fix."}, "result_dev_healthy": {"result": true, "level": "developing", "title": "Emerging Opportunity — Fragmented Support", "body": "Decent support, but split across multiple providers — a consolidation opportunity.", "points": ["Ask how many different providers or numbers they deal with", "Position a single point of contact as reducing complexity"], "next": "Upsell opportunity — position consolidation under one support model."}, "result_none_healthy": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Single point of contact and solid support already in place.", "points": ["Confirm satisfaction and contract terms for future reference"], "next": "Park — revisit at renewal."}, "result_mid_healthy": {"result": true, "level": "developing", "title": "Mostly Consolidated", "body": "Nearly there — a couple of stray relationships are usually easy to fold into a single model.", "points": ["Ask what those remaining separate items are", "Frame it as finishing the consolidation, not starting over"], "next": "Quick‑win opportunity — fold in the remaining stray relationships."}, "result_hot_internal": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Internal Team Stretched", "body": "An internal team being stretched thin as the business grows is a strong, relatable pain.", "points": ["Ask what's taking up the most internal time", "Position managed support as freeing up the internal team"], "next": "Strong opportunity — position as capacity relief for a stretched team."}, "result_warm_internal": {"result": true, "level": "developing", "title": "Emerging Opportunity — Sustainable For Now", "body": "No pressure yet, but growth will change that.", "points": ["Ask about growth plans or headcount trajectory", "Flag for follow‑up as they scale"], "next": "Nurture — revisit as they grow."}, "result_mid_internal": {"result": true, "level": "developing", "title": "Watching It Closely", "body": "Proactively watching for strain is a good sign — it means there's likely a clear trigger point you can plan around together.", "points": ["Ask what specifically they're watching for as a signal", "Offer to be the plan for when that signal appears"], "next": "Nurture — be the ready‑made plan for when the trigger hits."}}, "situationFollowUp": {"q": "How long has support been handled this way, and is anything changing — growth, new systems, a key person moving on?", "options": [{"label": "Been like this for years, nothing changing", "note": "Long-standing support setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've mentioned — customer experience, staff morale, or the wider team's ability to focus on their real jobs?", "options": [{"label": "Yes, it touches other things too", "note": "The impact extends beyond the immediate support issue."}, {"label": "No, that's really it", "note": "The impact stays contained to what's already been discussed."}]}, "distractorQuestions": {"situation": [{"text": "You've got good IT support in place, don't you?", "note": "Closed and leading — easy to just agree without it being true."}, {"text": "We've got a great support package on offer, want to hear about it?", "note": "That's pitching before you've found out whether their current support actually has a gap."}, {"text": "How's IT support going generally?", "note": "Too vague to point at anything concrete."}], "problem": [{"text": "You haven't had any real support issues, have you?", "note": "Closed and leading — invites a quick no."}, {"text": "We can sort your support setup — want a quote?", "note": "Jumps to a quote before confirming a genuine gap exists."}, {"text": "Anything else going on with support?", "note": "Too vague — build on what they actually just said."}], "implication": [{"text": "That's not really a big deal though, is it?", "note": "That's closed and leading, and it doesn't actually explore the cost or impact — the whole point of an implication question."}, {"text": "So we could sort that for you — want to hear how?", "note": "That jumps straight to the solution before you've actually established what the problem is costing them."}, {"text": "That must be a bit annoying, is it?", "note": "Closed and leading, and it minimises the problem — it invites a shrug instead of exploring what the issue actually costs them."}], "needpayoff": [{"text": "Well, let me know if you ever want to look at it.", "note": "Too passive — a strong need-payoff question invites a real answer and a next step, not an open-ended “whenever.”"}, {"text": "So what budget do you have for this?", "note": "That jumps straight to budget before you've actually confirmed they see the value — budget conversations land better once the value is clear."}, {"text": "Would you be interested in hearing more at some point?", "note": "Too vague and non-committal — it doesn't invite a real answer or move the conversation toward an actual next step."}]}, "primer": {"overview": "Support & Service Management is about what actually happens when something breaks — is there a clear process, a single point of contact, and an agreed response time, or does it depend entirely on whoever happens to be free that day?", "whyItMatters": "Relevant to any SME juggling multiple suppliers for different parts of their IT and telecoms, or relying on one stretched person (often the owner) to personally handle every technical problem that comes up.", "keyIndicators": ["No clear process for who fixes what when it breaks", "No agreed response time — just whenever someone gets to it", "One stretched person or team trying to cover everything themselves"], "compellingEvents": ["A recent problem that took far too long to resolve because nobody knew who to call", "The person who “handles all the IT stuff” leaving or being clearly overloaded", "Juggling multiple suppliers for network, phones, and backup with no single point of contact", "Growth reaching a point where ad-hoc support no longer scales"], "marketContext": "A lot of SMEs still rely on one person — often not even an IT professional — as the de facto single point of failure for every technical issue, which is a real, quietly-growing risk as the business grows.", "valueProp": "A single point of contact with a clear, agreed response time removes a very real stress point for the business owner, often for less cost and hassle than the ad-hoc setup they already have.", "exampleQuestions": {"situation": "“When something goes wrong today — network, phones, backup, anything — what actually happens? Who do you call, and how fast is it usually sorted?”", "problem": "“Has there been a time recently where something took far longer to fix than it should have?”", "implication": "“What does that delay actually cost you — lost time, frustrated staff, lost business?”", "needpayoff": "“If you had one number to call with a guaranteed response time, would that be worth having?”"}, "objections": [{"objection": "“We just call someone when something breaks, it's fine.”", "response": "Ask how long that usually takes to actually get resolved — “we manage” often hides real delays nobody's measured."}, {"objection": "“We don't want to lose the personal relationship with our current person.”", "response": "Acknowledge that's valuable, then ask what happens if that person is unavailable or leaves — a single point of contact is also a single point of failure."}, {"objection": "“Formal support contracts sound expensive.”", "response": "Ask what an unresolved issue actually costs them in downtime today — often more than a clear, agreed response time would cost to guarantee."}]}, "problemFollowUp": {"q": "Is that a one-off, or does it happen regularly with IT support?", "options": [{"label": "Pretty regular, not a one-off", "note": "The issue with IT support is recurring, not a one-time event."}, {"label": "Fairly rare, hasn't happened much", "note": "The issue with IT support has been infrequent so far."}]}, "needpayoffFollowUp": {"q": "Is this something you'd want to move on fairly soon, or more of a future consideration?", "options": [{"label": "Keen to move on this soon", "note": "There's real near-term urgency to act on this."}, {"label": "More of a future consideration", "note": "There's interest, but no immediate urgency to act."}]}}, {"id": "secure-access-edge", "name": "Secure Access Edge", "short": "Secure Access Edge", "icon": "🔑", "color": "#6B3E63", "blurb": "Can remote staff connect safely without opening the business up?", "criteria": ["Remote workers with no modern, secure way to connect", "Different security rules at different sites", "No idea what cloud apps staff are actually using"], "implicationQuestions": {"result_hot_remote": "If a remote worker's device were compromised right now, what could someone reach through that connection?", "result_mid_remote": "Do staff ever find workarounds because it's slow or awkward to use?", "result_warm_remote": "Does that cover every app they use, or just some of them?", "result_hot_branches": "If one site got compromised, how easily could that spread to the others given how different they are?", "result_mid_branches": "What's different about those particular sites — is there a reason they're the exception?", "result_warm_branches": "How do policy changes actually get rolled out today — one at a time, or all at once?", "result_hot_cloud": "If sensitive data ended up in an app nobody approved, how would you even find out?", "result_mid_cloud": "What other cloud tools do teams tend to reach for that wouldn't show up in that picture?", "result_warm_cloud": "What's the one blind spot that worries you most?", "result_dev_lowneed": "When that lands, what would it cost to not have the right access model already in place?", "result_mid_lowneed": "What would need to happen for it to go from a conversation to an actual plan?", "result_none_lowneed": "Is there anything that would change that — growth, a new hire working remotely, anything like that?"}, "needPayoff": {"remote_probe": "If every remote connection was verified and least‑privilege by default, would that close the gap?", "branches_probe": "If every site ran under the exact same policy from one place, would that remove the inconsistency risk?", "cloud_probe": "If you had full visibility and control over cloud app usage, would that be worth having today?", "lowneed_probe": "If the access model was already future‑proofed before that change lands, would that make it a non‑issue?"}, "tree": {"start": {"type": "situation", "q": "Do you have staff or branches connecting to company systems from outside a single, secured office — remote workers, multiple sites, cloud apps?", "options": [{"label": "Yes, remote workers with no real secure access layer", "next": "remote_probe"}, {"label": "Yes, multiple branches or sites", "next": "branches_probe"}, {"label": "We're heavy users of cloud apps like M365 and other SaaS tools", "next": "cloud_probe"}, {"label": "No, everyone works from one secured office", "next": "lowneed_probe"}]}, "remote_probe": {"type": "problem", "q": "How do they connect today — a traditional VPN, nothing at all, or something else?", "options": [{"label": "Nothing, or an old / basic VPN", "next": "result_hot_remote"}, {"label": "An old VPN that's clunky but technically works", "next": "result_mid_remote"}, {"label": "Some kind of modern secure access already", "next": "result_warm_remote"}]}, "branches_probe": {"type": "problem", "q": "How are those sites connected and secured — is policy consistent across all of them?", "options": [{"label": "Inconsistent — each site is a bit different", "next": "result_hot_branches"}, {"label": "Mostly consistent, with one or two exceptions", "next": "result_mid_branches"}, {"label": "Fairly consistent already", "next": "result_warm_branches"}]}, "cloud_probe": {"type": "problem", "q": "Do you have visibility into what cloud apps staff are actually using, and any control over risky ones — shadow IT?", "options": [{"label": "No visibility or control", "next": "result_hot_cloud"}, {"label": "Some visibility through M365, but not third‑party apps", "next": "result_mid_cloud"}, {"label": "Some visibility, not full control", "next": "result_warm_cloud"}]}, "lowneed_probe": {"type": "problem", "q": "Any plans to change that — new sites, remote hires, more cloud adoption?", "options": [{"label": "Yes, that's likely coming", "next": "result_dev_lowneed"}, {"label": "It's come up in conversation but nothing's planned", "next": "result_mid_lowneed"}, {"label": "No, not really", "next": "result_none_lowneed"}]}, "result_hot_remote": {"result": true, "level": "qualified", "title": "Qualified Opportunity — No Modern Secure Access", "body": "Remote workers with no zero‑trust layer is a significant, fixable exposure.", "points": ["Ask what data and systems remote workers can actually reach", "Position modern secure remote access (sometimes called Zero Trust or ZTNA) as the starting point"], "next": "Strong opportunity — start with modern secure remote access for remote workers."}, "result_warm_remote": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Coverage", "body": "Some modern access already exists — worth checking how complete it really is.", "points": ["Ask if it covers all apps or just some", "Look for gaps to extend coverage"], "next": "Nurture — probe for coverage gaps to extend."}, "result_mid_remote": {"result": true, "level": "developing", "title": "Outdated But Functional VPN", "body": "A working‑but‑clunky VPN often means workarounds and shadow IT creep in — the risk is in what people do to avoid using it.", "points": ["Ask if staff ever avoid using it because it's slow or awkward", "Modern secure access usually improves both security and day-to-day usability"], "next": "Upsell — position modern access as solving usability, not just security."}, "result_hot_branches": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Inconsistent Branch Security", "body": "Inconsistent policy across sites is a real compliance and risk gap.", "points": ["Map out how many sites and what's different about each", "Position one centralised secure access platform (sometimes called SASE) for consistent policy across every site"], "next": "Strong opportunity — propose one centralised secure access platform across all sites."}, "result_warm_branches": {"result": true, "level": "developing", "title": "Emerging Opportunity — Mostly Consistent", "body": "Reasonably consistent already — a lighter opportunity around centralisation or visibility.", "points": ["Ask how policy changes get rolled out today", "Introduce centralised management as an efficiency gain"], "next": "Nurture — position as efficiency, not urgency."}, "result_mid_branches": {"result": true, "level": "developing", "title": "Mostly Consistent, Known Exceptions", "body": "Known exceptions are actually a good sign — they're aware of the gap, which makes it easier to close.", "points": ["Ask specifically which sites are the exceptions and why", "Frame it as tidying up a known issue, not a full overhaul"], "next": "Quick‑win opportunity — close the specific known exceptions."}, "result_hot_cloud": {"result": true, "level": "qualified", "title": "Qualified Opportunity — Shadow IT / Cloud App Risk", "body": "No visibility or control over cloud app usage is a growing, real risk — data leakage and compliance exposure.", "points": ["Ask about any known incidents of data ending up in the wrong place", "Position a cloud app visibility and control tool (sometimes called CASB) as the fix"], "next": "Strong opportunity — lead with visibility and control over cloud app usage."}, "result_warm_cloud": {"result": true, "level": "developing", "title": "Emerging Opportunity — Partial Visibility", "body": "Some visibility already exists — extend it to full control.", "points": ["Ask what's still a blind spot", "Position as extending existing tools, not replacing them"], "next": "Nurture — extend existing visibility to full control."}, "result_mid_cloud": {"result": true, "level": "developing", "title": "Partial Cloud Visibility", "body": "Native visibility from one platform rarely extends to every app staff actually use — the real risk often lives in the blind spot.", "points": ["Ask what other cloud tools teams use day to day", "Position full cloud app visibility as extending what they already have"], "next": "Upsell — extend existing visibility to the full cloud app estate."}, "result_dev_lowneed": {"result": true, "level": "developing", "title": "Emerging Opportunity — Future Need", "body": "No current need, but change is coming.", "points": ["Get a rough timeline", "Flag for follow‑up nearer the change"], "next": "Nurture — revisit nearer the change."}, "result_none_lowneed": {"result": true, "level": "none", "title": "No Immediate Opportunity", "body": "Single‑site, fully office‑based — low priority for Secure Access Edge today.", "points": ["Note for future reference"], "next": "Park — low priority today."}, "result_mid_lowneed": {"result": true, "level": "surface", "title": "On the Radar, Not Planned", "body": "Early awareness without a plan — a light touchpoint now can position you well for when it does become concrete.", "points": ["Ask what would trigger it becoming a real plan", "Stay lightly in touch rather than pushing"], "next": "Very light nurture — stay visible for when it becomes concrete."}}, "situationFollowUp": {"q": "How long has remote or multi-site access been set up this way, and is anything changing — new sites, more remote staff, more cloud apps?", "options": [{"label": "Been like this for a while, nothing changing", "note": "Long-standing access setup, no near-term change."}, {"label": "Something's changing soon", "note": "A change is coming that's a natural trigger to revisit this."}]}, "implicationFollowUp": {"q": "Does this reach beyond what you've said — data across multiple sites, compliance, or trust if something were exposed?", "options": [{"label": "Yes, it goes wider than that", "note": "The impact extends beyond the immediate issue into compliance or trust."}, {"label": "No, that's really the whole picture", "note": "The impact stays contained to what's already been discussed."}]}, "distractorQuestions": {"situation": [{"text": "Remote access is all secure, isn't it?", "note": "Closed and leading — easy for them to just agree without it reflecting reality."}, {"text": "We've got a great secure access package, want to hear about it?", "note": "That's pitching before you've established whether there's a genuine gap here."}, {"text": "How's remote access going generally?", "note": "Too vague to surface anything specific."}], "problem": [{"text": "Remote access hasn't caused any real issues, has it?", "note": "Closed and leading — easy to just say no."}, {"text": "We can sort your remote access setup — want a quote?", "note": "Jumps to a quote before confirming there's a real problem."}, {"text": "Anything else going on with remote access?", "note": "Too vague — follow up on what they specifically said."}], "implication": [{"text": "That's not really a big deal though, is it?", "note": "That's closed and leading, and it doesn't actually explore the cost or impact — the whole point of an implication question."}, {"text": "So we could sort that for you — want to hear how?", "note": "That jumps straight to the solution before you've actually established what the problem is costing them."}, {"text": "That must be a bit annoying, is it?", "note": "Closed and leading, and it minimises the problem — it invites a shrug instead of exploring what the issue actually costs them."}], "needpayoff": [{"text": "Well, let me know if you ever want to look at it.", "note": "Too passive — a strong need-payoff question invites a real answer and a next step, not an open-ended “whenever.”"}, {"text": "So what budget do you have for this?", "note": "That jumps straight to budget before you've actually confirmed they see the value — budget conversations land better once the value is clear."}, {"text": "Would you be interested in hearing more at some point?", "note": "Too vague and non-committal — it doesn't invite a real answer or move the conversation toward an actual next step."}]}, "primer": {"overview": "Secure Access Edge covers how remote staff and multiple sites connect securely to company systems and cloud apps — sometimes using modern approaches like Zero Trust (often shortened to ZTNA) instead of a traditional VPN, or one centralised platform (sometimes called SASE) to keep security policy consistent everywhere rather than different rules at every site.", "whyItMatters": "Relevant to businesses with remote workers, multiple branches or sites, or heavy use of cloud apps — anywhere the old model of “everyone connects from inside one secure office” no longer reflects how people actually work.", "keyIndicators": ["Remote workers with no modern, secure way to connect — still relying on an old-style VPN or nothing at all", "Different security rules at different sites, with no consistency", "No idea what cloud apps staff are actually using day to day"], "compellingEvents": ["A shift to more remote working that outgrew an old VPN setup", "Opening new sites or branches, each currently set up slightly differently", "Discovering staff are using cloud apps nobody in the business actually approved or knows about", "A security incident tied to weak remote access controls"], "marketContext": "As work spreads across homes, branches, and cloud apps rather than one office, older security models built around a single physical perimeter increasingly don't match how the business actually operates day to day.", "valueProp": "Modern secure access lets staff connect safely from anywhere, with one consistent policy everywhere — simpler to manage than a patchwork of different rules per site, and more secure too.", "exampleQuestions": {"situation": "“Do you have staff or branches connecting to company systems from outside a single, secured office — remote workers, multiple sites, cloud apps?”", "problem": "“How are they connecting today — a traditional VPN, nothing formal, or something else?”", "implication": "“If someone accessed your systems insecurely and something went wrong, what would that actually cost you?”", "needpayoff": "“If everyone could connect safely and consistently, no matter where they're working from, would that be worth looking at?”"}, "objections": [{"objection": "“Our VPN works fine for remote access.”", "response": "Ask how it's actually managed day to day — older VPNs are often all-or-nothing access, which is a bigger risk than it first appears."}, {"objection": "“We don't have that many remote workers or sites.”", "response": "Ask if that's likely to grow, and note that inconsistent rules across even a few sites create real gaps that are hard to spot until something goes wrong."}, {"objection": "“This all sounds quite technical and complex.”", "response": "Reassure them the complexity is handled behind the scenes — for staff, it usually just means logging in normally, more securely."}], "regulatoryNote": "Worth knowing: secure remote access is one of the specific risk areas called out under the EU's NIS2 directive, currently being written into Irish law — see the Cyber Assurance section for the fuller regulatory picture."}, "problemFollowUp": {"q": "Is that a one-off, or does it happen regularly with remote access?", "options": [{"label": "Pretty regular, not a one-off", "note": "The issue with remote access is recurring, not a one-time event."}, {"label": "Fairly rare, hasn't happened much", "note": "The issue with remote access has been infrequent so far."}]}, "needpayoffFollowUp": {"q": "Is this something you'd want to move on fairly soon, or more of a future consideration?", "options": [{"label": "Keen to move on this soon", "note": "There's real near-term urgency to act on this."}, {"label": "More of a future consideration", "note": "There's interest, but no immediate urgency to act."}]}}];
const PIECES = PIECES_A.concat(PIECES_B);
const PIECE_IDS = PIECES.map(p=>p.id);
const PIECE_BY_ID = {};
PIECES.forEach(p=>PIECE_BY_ID[p.id]=p);

const LEVEL_ORDER = ['none','surface','developing','qualified'];
const LEVELS = {
  none:       {label:'No Pain',   short:'—',        color:'#7A8394', bg:'#F0EDF8'},
  surface:    {label:'Surface',   short:'Surface',   color:'#A2640A', bg:'#FDF1DC'},
  developing: {label:'Emerging',  short:'Emerging',  color:'#3478BC', bg:'#E8F2FD'},
  qualified:  {label:'Qualified', short:'Qualified', color:'#0A825A', bg:'#E1FAF0'}
};
const LEVEL_SCORE = {none:0, surface:1, developing:2, qualified:3};

/* ---- Shared closing guidance, keyed by final qualification level x how the
   customer responds to the Need-payoff question. Kept generic/reusable so we
   don't need hundreds of hand-written unique closing screens. ---- */
const CLOSE_TEMPLATES = {
  qualified:{
    positive:{ tag:'Ready to Move', ctaTier:'book_call', guidance:"They're bought into the value AND the pain is real — this is as good as discovery gets. Book a call with a specialist now to scope the solution and confirm decision-makers before momentum fades." },
    hesitant:{ tag:'Real Pain, Needs Reassurance', ctaTier:'book_call', guidance:"The pain is genuinely qualified, but something is holding them back from committing — cost, timing, trust, or another stakeholder needed. The fastest way through that is usually a short call with a specialist to answer their specific concern directly, rather than trying to resolve it yourself." }
  },
  developing:{
    positive:{ tag:'Warming Up', ctaTier:'book_call', guidance:"They like the sound of the fix even though the pain isn't fully proven yet. A short call with a specialist is a low-pressure way to go deeper — position it as exploring options, not proposing a solution." },
    hesitant:{ tag:'Early Stage, Low Urgency', ctaTier:'send_info', guidance:"Interest is lukewarm and the pain isn't sharp yet. Don't push for a call — send a short follow-up instead, log this clearly, and set a genuine trigger to revisit (renewal date, growth milestone, or a specific event)." }
  },
  surface:{
    positive:{ tag:'Curious But Unconfirmed', ctaTier:'send_info', guidance:"There's mild curiosity but nothing concrete underneath it yet. A light follow-up — a one-pager or short note — keeps the door open without overcommitting either side." },
    hesitant:{ tag:'Low Priority Today', ctaTier:'log_only', guidance:"Neither the pain nor the interest is strong enough to justify pushing further right now. Note it for the file and focus your remaining time on a more promising area." }
  },
  none:{
    positive:{ tag:'No Pain, Some Goodwill', ctaTier:'log_only', guidance:"There's no real problem here, but they're friendly to the conversation — a good sign for relationship-building even though there's nothing to close today." },
    hesitant:{ tag:'Not a Fit Today', ctaTier:'log_only', guidance:"No pain and no real interest — this area isn't worth further time in this conversation. Move on and revisit only if their circumstances change." }
  }
};

function buildCTA(piece, tier){
  if(tier==='book_call'){
    const subject = encodeURIComponent('Specialist call request — ' + piece.name);
    const body = encodeURIComponent(
      'Hi team,\n\nCould we get a ' + piece.short + ' specialist on a short call for a customer opportunity?\n\n' +
      'Area: ' + piece.name + '\n' +
      'Notes: [add customer name / account and opportunity detail here]\n\nThanks!'
    );
    return { label: '📅 Book a Call with a ' + piece.short + ' Specialist', href: 'mailto:?subject='+subject+'&body='+body };
  }
  if(tier==='send_info'){
    const subject = encodeURIComponent('Following up — ' + piece.name);
    const body = encodeURIComponent(
      'Hi,\n\nFollowing up with a bit more detail on ' + piece.name + ' for you to have a look through.\n\n' +
      '[Add specific detail or attach a one-pager]\n\nThanks!'
    );
    return { label: '✉️ Send Follow-Up Info', href: 'mailto:?subject='+subject+'&body='+body };
  }
  return null;
}

/* ---- Build the Implication + interactive Need-payoff layers onto every
   piece's tree. Situation -> Problem (3 options) -> Implication (2 options:
   high/low impact, tailored to the SPECIFIC problem answer just given) ->
   Need-payoff (2 options: positive/hesitant customer reaction) -> final
   Close screen with a concrete CTA (book a specialist call / send info /
   log only, depending on how qualified + how engaged they are). ---- */
function adjustLevel(level, impact){
  let idx = LEVEL_ORDER.indexOf(level);
  idx = impact==='high' ? Math.min(idx+1,3) : Math.max(idx-1,0);
  return LEVEL_ORDER[idx];
}
function transitionNote(fromLevel, toLevel, impact){
  if(toLevel===fromLevel){
    return impact==='high'
      ? "The impact holds this exactly where it was — now with real stakes confirmed behind it."
      : "The impact holds this at the same level — worth watching, but not enough alone to force urgency.";
  }
  const moved = LEVEL_ORDER.indexOf(toLevel) - LEVEL_ORDER.indexOf(fromLevel);
  return moved > 0
    ? "The implication answer actually strengthens this — the impact turned out bigger than the initial answer suggested."
    : "The implication answer softens this — the underlying issue is real, but the impact isn't significant enough yet to force urgency.";
}
function coreTitle(title){
  const idx = title.indexOf('—');
  if(idx!==-1) return title.slice(idx+1).trim();
  if(title==='No Immediate Opportunity') return 'Healthy — No Action Needed';
  if(title==='Follow-Up Required' || title==='Follow\u2011Up Required') return 'Needs Discovery';
  return title;
}

/* Severity-appropriate frequency follow-up (Option A fix).
   The problem answer already locks in a result severity BEFORE this follow-up
   is shown. So instead of a random one-off/regular coin-flip that could
   contradict a confirmed severe problem, both revealed answers in each bucket
   are consistent with that severity — a severe problem never reads as "rare",
   and a high-severity case can still carry a genuine, non-downgrading nuance
   (severe but concentrated at peak times). Shared across all pieces, like the
   implication/need-payoff option sets already are. */
const FREQ_FOLLOWUP = {
  high: {
    q: "How often does that actually bite — constant, or worse at certain times?",
    options: [
      { label: "Honestly, it's pretty much constant", freq: 'constant',
        note: "They confirmed it's a constant, recurring problem — consistent with the impact." },
      { label: "Worst at our busy times, but it's a real problem when it hits", freq: 'peak',
        note: "Severe but concentrated in peak periods — a genuine distinction, not a downgrade of the problem." }
    ]
  },
  med: {
    q: "How often does that come up — regularly, or more on and off?",
    options: [
      { label: "Regularly enough to be a real nuisance", freq: 'regular',
        note: "A recurring issue — happens often enough to matter." },
      { label: "It comes and goes — some weeks fine, some not", freq: 'intermittent',
        note: "Intermittent — worth understanding the pattern behind it." }
    ]
  },
  low: {
    q: "And how often does that actually happen for you?",
    options: [
      { label: "Only occasionally, if I'm honest", freq: 'occasional',
        note: "Occasional — low frequency, in line with this being a minor issue so far." },
      { label: "Pretty rare — more of a one-off really", freq: 'rare',
        note: "Rare/one-off — consistent with this not being a pressing problem today." }
    ]
  }
};
function severityBucket(level){
  if(level === 'qualified') return 'high';
  if(level === 'developing') return 'med';
  return 'low'; // surface | none
}
/* Severity-appropriate implication reveal (Option A extension).
   The problem answer locks in a result severity. A healthy/curious setup
   (none/surface) must not then "confirm" real present cost, compliance or
   public-trust exposure — that would contradict the problem answer just given.
   So the low bucket offers only proportionate, impact-free answers (which route
   to the _lo branch, where the wider-impact follow-up also stays "contained").
   developing/qualified keep the full high/low choice so a genuinely real
   problem can still escalate on impact. */
const IMPL_REVEAL = {
  high: [
    { label: 'It adds up — real cost, time or risk', impact: 'high' },
    { label: 'Manageable — not a big deal', impact: 'low' }
  ],
  med: [
    { label: 'It adds up — real cost, time or risk', impact: 'high' },
    { label: 'Manageable — not a big deal', impact: 'low' }
  ],
  low: [
    { label: "No, it's genuinely fine as it stands", impact: 'low' },
    { label: "Nothing pressing — though it's worth keeping half an eye on", impact: 'low' }
  ]
};
function buildTrees(){
  PIECES.forEach(piece=>{
    const newNodes = {};

    // ---- Situation layer: after the initial Situation answer, let the rep
    // choose to ask one more opening question before moving to Problem, or
    // skip straight to it. The follow-up's own answer doesn't change which
    // Problem question comes next — it only adds optional extra context —
    // so every branch still resolves to exactly the same set of outcomes. ----
    const startNode = piece.tree['start'];
    if(startNode && piece.situationFollowUp){
      startNode.options.forEach((opt, idx)=>{
        const originalNext = opt.next;
        const branchKey = 's' + idx;
        const choiceId = 'schoice_' + branchKey;
        const fuId = 'sfu_' + branchKey;
        newNodes[choiceId] = {
          type:'choice', stage:'situation',
          q:"Do you want to ask one more opening question to build a fuller picture, or move straight into it?",
          options:[
            {label:'Ask one more opening question', next: fuId},
            {label:'Move straight into the next question', next: originalNext}
          ]
        };
        newNodes[fuId] = {
          type:'situation',
          q: piece.situationFollowUp.q,
          options: piece.situationFollowUp.options.map(o=>({label:o.label, next: originalNext, note:o.note}))
        };
        opt.next = choiceId;
      });
    }

    // ---- Problem -> Implication (connected per-answer) ----
    Object.keys(piece.tree).forEach(nodeId=>{
      const node = piece.tree[nodeId];
      if(node.type !== 'problem') return;
      const npQuestion = piece.needPayoff[nodeId];
      node.options.forEach(opt=>{
        const baseId = opt.next;
        const base = piece.tree[baseId];
        if(!base || !base.result) return;
        // Implication question is looked up per SPECIFIC answer (baseId), not
        // shared across the whole problem node — connects directly to what
        // was just said rather than asking something generic.
        const qText = piece.implicationQuestions[baseId];
        const implId = 'impl_' + baseId;
        // ---- Problem follow-up layer: same optional "ask one more" pattern,
        // inserted between the Problem answer and the Implication question. ----
        const pchoiceId = baseId + '_pchoice';
        const pfuId = baseId + '_pfu';
        if(piece.problemFollowUp){
          newNodes[pchoiceId] = {
            type:'choice', stage:'problem',
            q:"Do you want to ask one more question to understand the problem better, or move to what it actually costs them?",
            options:[
              {label:'Ask one more problem question', next: pfuId},
              {label:'Move to the impact question', next: implId}
            ]
          };
          const freqSet = FREQ_FOLLOWUP[severityBucket(base.level)];
          newNodes[pfuId] = {
            type:'problem',
            q: freqSet.q,
            // Both options are consistent with the confirmed severity, so any
            // reveal is safe — no contradiction possible with the problem answer.
            severityBound: true,
            options: freqSet.options.map(o=>({label:o.label, next: implId, note:o.note, freq:o.freq}))
          };
        }

        const implSet = IMPL_REVEAL[severityBucket(base.level)];
        newNodes[implId] = {
          type:'implication',
          q: qText,
          // Reveal options bound to the confirmed severity: a healthy/curious
          // setup (none/surface) can never reveal "real cost, time or risk" —
          // that would contradict the problem answer just given. Both low-bucket
          // options route to the _lo branch, so the wider-impact follow-up there
          // also stays "contained". Only developing/qualified can escalate.
          severityBoundImpl: severityBucket(base.level),
          options: implSet.map(o=>({label:o.label, impact:o.impact, next: implId + (o.impact==='high' ? '_hi' : '_lo')}))
        };
        ['hi','lo'].forEach(tag=>{
          const impact = tag==='hi' ? 'high' : 'low';
          const finalLevel = adjustLevel(base.level, impact);
          const npId = implId + '_' + tag;

          // ---- Implication follow-up layer: same optional "ask one more"
          // pattern, inserted between the Implication answer and the
          // Need-payoff question. Purely additive context, doesn't change
          // the destination or the computed level. ----
          const ichoiceId = npId + '_ichoice';
          const ifuId = npId + '_ifu';
          if(piece.implicationFollowUp){
            newNodes[ichoiceId] = {
              type:'choice', stage:'implication',
              q:"Do you want to ask one more question about the impact, or move to the closing question?",
              options:[
                {label:'Ask one more impact question', next: ifuId},
                {label:'Move to the closing question', next: npId}
              ]
            };
            newNodes[ifuId] = {
              type:'implication',
              q: piece.implicationFollowUp.q,
              options: piece.implicationFollowUp.options.map(o=>({label:o.label, next: npId, note:o.note})),
              parentImpact: impact,   // 'high' or 'low' — whichever the primary Implication reveal just was
              reinforceIdx: 0         // option 0 ("goes wider") reinforces; option 1 ("that's the whole picture") contains — verified consistent across all pieces' authored implicationFollowUp content
            };
          }

          newNodes[npId] = {
            type:'needpayoff',
            q: npQuestion,
            options:[
              {label:'Positive — engages with it, sees the value', engagement:'positive', next: npId+'_pos'},
              {label:'Hesitant — non-committal or deflects', engagement:'hesitant', next: npId+'_hes'}
            ]
          };
          ['pos','hes'].forEach(etag=>{
            const engagement = etag==='pos' ? 'positive' : 'hesitant';
            const tmpl = CLOSE_TEMPLATES[finalLevel][engagement];
            const resultId = npId+'_'+etag;
            newNodes[resultId] = {
              result:true,
              level:finalLevel,
              title: coreTitle(base.title) + ' — ' + tmpl.tag,
              body: base.body,
              transition: transitionNote(base.level, finalLevel, impact),
              points: base.points,
              next: base.next,
              closeGuidance: tmpl.guidance,
              cta: buildCTA(piece, tmpl.ctaTier)
            };

            // ---- Need-payoff follow-up layer: same optional "ask one more"
            // pattern, inserted between the Need-payoff answer and the final
            // result. Purely additive context, doesn't change the outcome. ----
            if(piece.needpayoffFollowUp){
              const nchoiceId = resultId + '_nchoice';
              const nfuId = resultId + '_nfu';
              newNodes[nchoiceId] = {
                type:'choice', stage:'needpayoff',
                q:"Do you want to ask one more closing question, or wrap up here?",
                options:[
                  {label:'Ask one more closing question', next: nfuId},
                  {label:'Wrap up here', next: resultId}
                ]
              };
              newNodes[nfuId] = {
                type:'needpayoff',
                q: piece.needpayoffFollowUp.q,
                options: piece.needpayoffFollowUp.options.map(o=>({label:o.label, next: resultId, note:o.note})),
                parentEngagement: engagement,  // 'positive' or 'hesitant' — whichever the primary Need-payoff reveal just was
                reinforceIdx: 0                // option 0 ("keen to move soon") reinforces; option 1 ("future consideration") contains
              };
            }
          });
        });
        opt.next = piece.problemFollowUp ? pchoiceId : implId;
      });
    });
    Object.assign(piece.tree, newNodes);

    // Second pass: now that pchoice/nchoice nodes exist, point the Problem and
    // Need-payoff nodes' own options at the choice layer rather than straight
    // to the next stage — mirrors the existing implication-choice redirect.
    Object.keys(newNodes).forEach(id=>{
      const n = newNodes[id];
      if(n.type==='needpayoff' && /^impl_.+_(hi|lo)$/.test(id) && !/_nfu$/.test(id)){
        n.options.forEach(o=>{
          const nchoiceId = o.next + '_nchoice';
          if(piece.tree[nchoiceId]) o.next = nchoiceId;
        });
      }
    });

    // Second pass: now that implId nodes exist in newNodes, point their hi/lo
    // options at the implication-choice node rather than directly at need-payoff.
    Object.keys(newNodes).forEach(id=>{
      const n = newNodes[id];
      if(n.type==='implication' && /^impl_/.test(id) && !/_ifu$/.test(id)){
        n.options.forEach(o=>{
          const ichoiceId = o.next + '_ichoice';
          if(piece.tree[ichoiceId]) o.next = ichoiceId;
        });
      }
    });
  });
}
buildTrees();


